queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?librarians a :Librarians .
    ?librarians p:name ?name .
    ?librarians p:location ?location_f .
    FILTER(STR(?location_f) = "University's Main Library")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?archivists a :Archivists .
    ?archivists p:name ?name .
    ?archivists p:location ?location_f .
    FILTER(STR(?location_f) = "University's Main Library")
    BIND(?name AS ?o0)
  }
}

